# Unit Tests for `gcd` Function

```python
import pytest


def gcd(a: int, b: int) -> int:
    while b:
        a, b = b, a % b
    return abs(a)


class TestGcdHappyPath:
    """Tests for typical, expected inputs."""

    def test_two_positive_coprime_numbers(self):
        assert gcd(7, 13) == 1

    def test_two_positive_with_common_factor(self):
        assert gcd(12, 18) == 6

    def test_one_divides_the_other(self):
        assert gcd(10, 5) == 5
        assert gcd(5, 10) == 5

    def test_equal_numbers(self):
        assert gcd(7, 7) == 7

    def test_large_numbers(self):
        assert gcd(123456, 789012) == 12

    def test_prime_numbers(self):
        assert gcd(17, 19) == 1

    def test_powers_of_two(self):
        assert gcd(64, 16) == 16

    def test_consecutive_integers_are_coprime(self):
        assert gcd(100, 101) == 1

    def test_one_with_anything_is_one(self):
        assert gcd(1, 999) == 1
        assert gcd(999, 1) == 1


class TestGcdEdgeCases:
    """Tests for boundary and edge cases."""

    def test_both_zero(self):
        # By convention, gcd(0, 0) = 0
        assert gcd(0, 0) == 0

    def test_zero_and_positive(self):
        # gcd(0, n) = n
        assert gcd(0, 5) == 5

    def test_positive_and_zero(self):
        # gcd(n, 0) = n
        assert gcd(5, 0) == 5

    def test_zero_and_negative(self):
        # gcd should return absolute value
        assert gcd(0, -5) == 5

    def test_negative_and_zero(self):
        assert gcd(-5, 0) == 5

    def test_both_negative(self):
        assert gcd(-12, -18) == 6

    def test_negative_and_positive(self):
        assert gcd(-12, 18) == 6

    def test_positive_and_negative(self):
        assert gcd(12, -18) == 6

    def test_very_large_numbers(self):
        assert gcd(10**18, 10**18) == 10**18

    def test_very_large_coprime(self):
        # Two large primes
        assert gcd(2**61 - 1, 2**31 - 1) == 1

    def test_identity_with_one(self):
        assert gcd(1, 1) == 1

    def test_negative_one(self):
        assert gcd(-1, -1) == 1

    @pytest.mark.parametrize("a,b,expected", [
        (48, 36, 12),
        (54, 24, 6),
        (101, 103, 1),
        (1000, 100, 100),
        (270, 192, 6),
        (-48, 36, 12),
        (48, -36, 12),
        (-48, -36, 12),
        (0, 7, 7),
        (7, 0, 7),
    ])
    def test_parametrized_cases(self, a, b, expected):
        assert gcd(a, b) == expected


class TestGcdProperties:
    """Tests verifying mathematical properties of gcd."""

    @pytest.mark.parametrize("a,b", [
        (12, 18),
        (100, 75),
        (7, 13),
        (1024, 768),
    ])
    def test_commutativity(self, a, b):
        """gcd(a, b) == gcd(b, a)"""
        assert gcd(a, b) == gcd(b, a)

    @pytest.mark.parametrize("a,b,c", [
        (12, 18, 24),
        (10, 20, 30),
        (7, 14, 21),
    ])
    def test_associativity(self, a, b, c):
        """gcd(gcd(a, b), c) == gcd(a, gcd(b, c))"""
        assert gcd(gcd(a, b), c) == gcd(a, gcd(b, c))

    @pytest.mark.parametrize("a,b", [
        (12, 18),
        (100, 75),
        (1024, 768),
        (123, 456),
    ])
    def test_result_divides_both(self, a, b):
        """The gcd should divide both numbers."""
        result = gcd(a, b)
        assert a % result == 0
        assert b % result == 0

    @pytest.mark.parametrize("a,b", [
        (12, 18),
        (-12, 18),
        (12, -18),
        (-12, -18),
    ])
    def test_result_always_non_negative(self, a, b):
        """gcd is always non-negative."""
        assert gcd(a, b) >= 0


